import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        arr.sort(reverse=True)
        ok = True
        for i in range(1, n):
            if arr[i] == arr[i-1]:
                ok = False
                break
        if not ok:
            out_lines.append('-1')
        else:
            out_lines.append(' '.join(map(str, arr)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

